import{_ as a,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Миграция аккаунтов: Резервное копирование/Горячая миграция | Antigravity Manager","description":"Изучите резервное копирование и миграцию аккаунтов Antigravity Manager. Поддержка импорта/экспорта JSON, горячая миграция из Antigravity/IDE, миграция из каталога данных V1 и автоматическая синхронизация текущего аккаунта.","frontmatter":{"title":"Миграция аккаунтов: Резервное копирование/Горячая миграция | Antigravity Manager","sidebarTitle":"Миграция пула аккаунтов за 3 минуты","subtitle":"Миграция аккаунтов: Резервное копирование/Горячая миграция","description":"Изучите резервное копирование и миграцию аккаунтов Antigravity Manager. Поддержка импорта/экспорта JSON, горячая миграция из Antigravity/IDE, миграция из каталога данных V1 и автоматическая синхронизация текущего аккаунта.","tags":["Управление аккаунтами","Резервное копирование","Миграция","Импорт/Экспорт","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"ru/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function o(n,t,l,d,c,h){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="резервное-копирование-и-миграция-аккаунтов-импорт-экспорт-горячая-миграция-v1-db" tabindex="-1">Резервное копирование и миграция аккаунтов: Импорт/Экспорт, горячая миграция V1/DB <a class="header-anchor" href="#резервное-копирование-и-миграция-аккаунтов-импорт-экспорт-горячая-миграция-v1-db" aria-label="Permalink to &quot;Резервное копирование и миграция аккаунтов: Импорт/Экспорт, горячая миграция V1/DB&quot;">​</a></h1><p>То, что вы действительно хотите «резервировать» — это не число квот, а <code>refresh_token</code>, позволяющий аккаунту снова войти. Этот урок объясняет несколько методов миграции Antigravity Tools: импорт/экспорт JSON, импорт из <code>state.vscdb</code>, импорт из каталога данных V1 и способ работы автоматической синхронизации.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>Экспортировать пул аккаунтов в один JSON-файл (содержащий только email + refresh_token)</li><li>Импортировать этот JSON на новом компьютере для быстрого восстановления пула аккаунтов</li><li>Импортировать «текущий вошедший аккаунт» напрямую из <code>state.vscdb</code> Antigravity/IDE (поддерживается путь по умолчанию и пользовательский путь)</li><li>Автоматически сканировать и импортировать старые аккаунты из каталога данных V1</li><li>Понимать, что именно делает «автоматическая синхронизация текущего аккаунта» и когда она пропускает</li></ul><h2 id="текущие-проблемы" tabindex="-1">Текущие проблемы <a class="header-anchor" href="#текущие-проблемы" aria-label="Permalink to &quot;Текущие проблемы&quot;">​</a></h2><ul><li>После переустановки системы/смены компьютера нужно заново добавлять пул аккаунтов, что стоит дорого</li><li>Вы сменили вошедший аккаунт в Antigravity/IDE, но «текущий аккаунт» в Manager не изменился</li><li>Ранее вы использовали V1/скриптовую версию, у вас только старые файлы данных, не знаете, можно ли напрямую мигрировать</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li>Вы хотите перенести пул аккаунтов на другой компьютер (десктоп/сервер/контейнер)</li><li>Вы используете Antigravity как «авторитетный вход», хотите, чтобы Manager автоматически синхронизировал текущий аккаунт</li><li>Вы хотите перенести аккаунты из старой версии (каталог данных V1)</li></ul><h2 id="🎒-подготовка" tabindex="-1">🎒 Подготовка <a class="header-anchor" href="#🎒-подготовка" aria-label="Permalink to &quot;🎒 Подготовка&quot;">​</a></h2><ul><li>Вы уже можете открыть Antigravity Tools и в пуле аккаунтов есть хотя бы один аккаунт</li><li>Вы знаете, что данные аккаунтов — это чувствительная информация (особенно <code>refresh_token</code>)</li></ul><div class="warning custom-block"><p class="custom-block-title">Напоминание о безопасности: относитесь к файлам резервных копий как к паролям</p><p>Экспортированный JSON-файл содержит <code>refresh_token</code>. Любой, кто его получит, может использовать его для обновления access token. Не загружайте файлы резервных копий на публичные ссылки облачных хранилищ, не отправляйте в группы, не коммитите в Git.</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>«Миграция» в Antigravity Tools — это по сути две вещи:</p><ol><li>Найти доступный <code>refresh_token</code></li><li>Использовать его для получения access token, запросить у Google реальный email и записать аккаунт в локальный пул</li></ol><p>Оно предоставляет три входа:</p><ul><li>Импорт/экспорт JSON: подходит, когда вы хотите сделать «контролируемую резервную копию»</li><li>Импорт из DB: подходит, когда вы рассматриваете состояние входа Antigravity/IDE как авторитетный источник (по умолчанию ищет <code>state.vscdb</code>, также поддерживает ручной выбор файла)</li><li>Импорт V1: подходит для автоматического сканирования и миграции из старого каталога данных</li></ul><p>Ещё есть «автоматическая синхронизация»: она периодически считывает refresh_token из DB, если он отличается от текущего аккаунта Manager, автоматически выполняет импорт из DB; если такой же — пропускает (экономит трафик).</p><h2 id="пошаговое-руководство" tabindex="-1">Пошаговое руководство <a class="header-anchor" href="#пошаговое-руководство" aria-label="Permalink to &quot;Пошаговое руководство&quot;">​</a></h2><h3 id="шаг-1-экспорт-пула-аккаунтов-резервная-копия-json" tabindex="-1">Шаг 1: Экспорт пула аккаунтов (резервная копия JSON) <a class="header-anchor" href="#шаг-1-экспорт-пула-аккаунтов-резервная-копия-json" aria-label="Permalink to &quot;Шаг 1: Экспорт пула аккаунтов (резервная копия JSON)&quot;">​</a></h3><p><strong>Зачем</strong> Это самый стабильный и контролируемый способ миграции. Получив один файл, вы можете восстановить пул аккаунтов на другом компьютере.</p><p>Действие: перейдите на страницу <code>Accounts</code>, нажмите кнопку экспорта.</p><ul><li>Если вы настроили <code>default_export_path</code> в настройках, экспорт напрямую запишется в этот каталог и будет использовать имя файла <code>antigravity_accounts_YYYY-MM-DD.json</code>.</li><li>Если каталог по умолчанию не настроен, появится системное диалоговое окно сохранения для выбора пути.</li></ul><p>Содержимое экспортированного файла примерно такое (каждый элемент в массиве содержит только необходимые поля):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: На странице появляется сообщение об успешном экспорте и отображается путь сохранения.</p><h3 id="шаг-2-импорт-json-на-новом-компьютере-восстановление-пула-аккаунтов" tabindex="-1">Шаг 2: Импорт JSON на новом компьютере (восстановление пула аккаунтов) <a class="header-anchor" href="#шаг-2-импорт-json-на-новом-компьютере-восстановление-пула-аккаунтов" aria-label="Permalink to &quot;Шаг 2: Импорт JSON на новом компьютере (восстановление пула аккаунтов)&quot;">​</a></h3><p><strong>Зачем</strong> Импорт вызовет по очереди логику «добавления аккаунта», использует <code>refresh_token</code> для получения реального email и записи в пул аккаунтов.</p><p>Действие: всё ещё на странице <code>Accounts</code>, нажмите «Импорт JSON», выберите только что экспортированный файл.</p><p>Требования к формату (минимум 1 действительная запись):</p><ul><li>Должен быть массив JSON</li><li>Система импортирует только записи, содержащие <code>refresh_token</code> и начинающиеся с <code>1//</code></li></ul><p><strong>Что вы должны увидеть</strong>: После импорта в списке аккаунтов появляются импортированные аккаунты.</p><div class="tip custom-block"><p class="custom-block-title">Если при импорте Proxy запущен</p><p>После каждого успешного «добавления аккаунта» бэкенд пытается перезагрузить пул токенов прокси, чтобы новый аккаунт сразу生效.</p></div><h3 id="шаг-3-импорт-«текущего-вошедшего-аккаунта»-из-state-vscdb" tabindex="-1">Шаг 3: Импорт «текущего вошедшего аккаунта» из <code>state.vscdb</code> <a class="header-anchor" href="#шаг-3-импорт-«текущего-вошедшего-аккаунта»-из-state-vscdb" aria-label="Permalink to &quot;Шаг 3: Импорт «текущего вошедшего аккаунта» из \`state.vscdb\`&quot;">​</a></h3><p><strong>Зачем</strong> Иногда вы не хотите поддерживать файлы резервных копий, а хотите «использовать состояние входа Antigravity/IDE как авторитет». Импорт из DB подготовлен для этого сценария.</p><p>Действие: перейдите на страницу <code>Accounts</code>, нажмите <strong>Add Account</strong>, переключитесь на вкладку <code>Import</code>:</p><ul><li>Нажмите «Импорт из базы данных» (использует путь DB по умолчанию)</li><li>Или нажмите «Custom DB (state.vscdb)» для ручного выбора файла <code>*.vscdb</code></li></ul><p>Путь DB по умолчанию кроссплатформенный (также приоритетно распознаёт <code>--user-data-dir</code> или portable mode):</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-tNSuw" id="tab-ra7AjM3" checked><label data-title="macOS" for="tab-ra7AjM3">macOS</label><input type="radio" name="group-tNSuw" id="tab-KnKufkb"><label data-title="Windows" for="tab-KnKufkb">Windows</label><input type="radio" name="group-tNSuw" id="tab-xBep16P"><label data-title="Linux" for="tab-xBep16P">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage\\state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>Что вы должны увидеть</strong>:</p><ul><li>После успешного импорта этот аккаунт будет автоматически установлен как «текущий аккаунт» Manager</li><li>Автоматически запустится обновление квоты</li></ul><h3 id="шаг-4-миграция-из-каталога-данных-v1-импорт-старои-версии" tabindex="-1">Шаг 4: Миграция из каталога данных V1 (импорт старой версии) <a class="header-anchor" href="#шаг-4-миграция-из-каталога-данных-v1-импорт-старои-версии" aria-label="Permalink to &quot;Шаг 4: Миграция из каталога данных V1 (импорт старой версии)&quot;">​</a></h3><p><strong>Зачем</strong> Если вы раньше использовали V1/скриптовую версию, Manager позволяет напрямую сканировать старый каталог данных и попробовать импорт.</p><p>Действие: на вкладке <code>Import</code> нажмите «Импорт V1».</p><p>Он будет искать этот путь в вашем домашнем каталоге (и файл индекса в нём):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: После импорта аккаунты появляются в списке; если файл индекса не найден, бэкенд вернёт ошибку <code>V1 account data file not found</code>.</p><h3 id="шаг-5-опционально-включите-«автоматическую-синхронизацию-текущего-аккаунта»" tabindex="-1">Шаг 5 (опционально): Включите «автоматическую синхронизацию текущего аккаунта» <a class="header-anchor" href="#шаг-5-опционально-включите-«автоматическую-синхронизацию-текущего-аккаунта»" aria-label="Permalink to &quot;Шаг 5 (опционально): Включите «автоматическую синхронизацию текущего аккаунта»&quot;">​</a></h3><p><strong>Зачем</strong> Когда вы переключаете вошедший аккаунт в Antigravity/IDE, Manager может через фиксированный интервал проверить, изменился ли refresh_token в DB, и при изменении автоматически импортировать.</p><p>Действие: перейдите в <code>Settings</code>, включите <code>auto_sync</code> и установите <code>sync_interval</code> (единица: секунды).</p><p><strong>Что вы должны увидеть</strong>: После включения сразу выполнится одна синхронизация; затем периодически по интервалу. Если refresh_token в DB такой же, как у текущего аккаунта, он пропустит, не будет повторно импортировать.</p><h2 id="контрольные-точки-✅" tabindex="-1">Контрольные точки ✅ <a class="header-anchor" href="#контрольные-точки-✅" aria-label="Permalink to &quot;Контрольные точки ✅&quot;">​</a></h2><ul><li>В списке <code>Accounts</code> вы видите импортированные аккаунты</li><li>Вы видите, что «текущий аккаунт» переключился на желаемый (при импорте из DB автоматически устанавливается как текущий)</li><li>После запуска Proxy новые импортированные аккаунты могут нормально использоваться для запросов (ориентируйтесь на фактические результаты вызова)</li></ul><h2 id="частые-ошибки" tabindex="-1">Частые ошибки <a class="header-anchor" href="#частые-ошибки" aria-label="Permalink to &quot;Частые ошибки&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ситуация</th><th>Что вы можете сделать (❌)</th><th>Рекомендуемый подход (✓)</th></tr></thead><tbody><tr><td>Безопасность файла резервной копии</td><td>Отправляете экспортированный JSON как обычный файл конфигурации</td><td>Относитесь к JSON как к паролю, минимизируйте распространение, избегайте публичного доступа</td></tr><tr><td>Ошибка импорта JSON</td><td>JSON не массив, или у refresh_token нет префикса <code>1//</code></td><td>Используйте JSON, экспортированный этим проектом, как шаблон, сохраняйте имена полей и структуру одинаковыми</td></tr><tr><td>Импорт из DB не находит данные</td><td>Antigravity ни разу не входил, или в DB нет <code>jetskiStateSync.agentManagerInitState</code></td><td>Сначала подтвердите, что Antigravity/IDE вошёл, затем попробуйте импортировать; при необходимости используйте Custom DB для выбора правильного файла</td></tr><tr><td>Аккаунты недоступны после импорта V1</td><td>Старый refresh_token недействителен</td><td>Удалите этот аккаунт и добавьте снова через OAuth/новый refresh_token (ориентируйтесь на сообщение об ошибке)</td></tr><tr><td>auto_sync слишком часто</td><td><code>sync_interval</code> установлен очень маленьким, часто сканируется DB</td><td>Рассматривайте это как «следование состоянию», установите интервал на приемлемую частоту</td></tr></tbody></table><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li>Экспорт/импорт JSON — самый контролируемый способ миграции: в файле резервной копии сохраняется только <code>email + refresh_token</code></li><li>Импорт из DB подходит для «с учётом текущего вошедшего аккаунта Antigravity/IDE» и автоматически устанавливается как текущий аккаунт Manager</li><li>Импорт V1 сканирует <code>~/.antigravity-agent</code> и совместим с несколькими старыми форматами</li><li>auto_sync сравнивает refresh_token; если такой же, пропускает, не будет повторно импортировать</li></ul><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы начнём реально использовать «мигрированный пул аккаунтов»: <strong><a href="./../proxy-and-first-client/">Запуск локального прокси и подключение первого клиента (healthz + конфигурация SDK)</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как запустить/остановить Proxy и использовать <code>/healthz</code> для минимальной проверки</li><li>Как настроить Base URL в SDK/клиенте</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы раскрыть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Экспорт/импорт JSON Accounts (<code>save_text_file</code> / <code>read_text_file</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Экспорт JSON аккаунтов на Dashboard</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Вкладка Import: кнопки импорта DB / Custom DB / V1</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>Добавление аккаунта: игнорировать email фронтенда, использовать refresh_token для получения реального email, автоматически обновлять квоту, горячая перезагрузка Proxy</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Импорт DB: извлечение refresh_token из <code>state.vscdb</code> (ItemTable + base64 + protobuf)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>После импорта из DB автоматически установить как «текущий аккаунт» и обновить квоту</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L495-L511" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>495-511</td></tr><tr><td>auto_sync: сравнить refresh_token, если такой же пропустить; при изменении запустить импорт из DB</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>Фоновая задача фронтенда: периодический вызов <code>syncAccountFromDb()</code> по <code>sync_interval</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
